{"command": "# Try calling Alibaba Tongyi Wanxiang API for image generation with reference image
# First, let's check the API by trying a synchronous call

PROMPT="参考照片中这个男孩的形象，画一张他7-10岁时的写实肖像：同样的脸型和气质（戴细框眼镜、穿棕色连帽外套、安静微笑的男孩），但面容更稚嫩。背景简单干净。写实风格。"

# Base64 encode the reference image
IMG_B64=$(base64 -w0 /root/.openclaw/media/qqbot/downloads/F4FFB2D960F7DCE64B79DFBDE9AC7DEF_1780268182259_7d8b9a.jpg)

# Try the Alibaba DashScope API
curl -s -X POST "https://dashscope.aliyuncs.com/api/v1/services/aigc/text2image/image-synthesis" \
  -H "Authorization: Bearer $DASHSCOPE_API_KEY" \
  -H "Content-Type: application/json" \
  -d "{
    \"model\": \"wanx2.1-t2i-turbo\",
    \"input\": {
      \"prompt\": \"$PROMPT\",
      \"negative_prompt\": \"照片、现实照片、肤色不均、畸形、扭曲、模糊、低质量\",
      \"reference_image\": \"$IMG_B64\"
    },
    \"parameters\": {
      \"size\": \"1024*1024\",
      \"n\": 1
    }
  }" 2>&1 | head -200", "timeout": 120}

